// API utilities for TypeArena (placeholder functions with mock data)
import { mockUsers, mockTournaments, mockLeaderboard, mockRaceResults } from './mockData';

const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:3001/api';

// User APIs
export const fetchCurrentUser = async () => {
  try {
    // TODO: Replace with actual API call
    // const response = await fetch(`${API_BASE_URL}/user/me`);
    // return response.json();
    
    // Mock implementation
    return new Promise((resolve) => {
      setTimeout(() => {
        const user = localStorage.getItem('typearena_user');
        resolve(user ? JSON.parse(user) : null);
      }, 300);
    });
  } catch (error) {
    console.error('Error fetching user:', error);
    return null;
  }
};

export const loginUser = async (email, password) => {
  try {
    // TODO: Replace with actual API call
    // const response = await fetch(`${API_BASE_URL}/auth/login`, {
    //   method: 'POST',
    //   headers: { 'Content-Type': 'application/json' },
    //   body: JSON.stringify({ email, password }),
    // });
    // return response.json();
    
    // Mock implementation
    return new Promise((resolve) => {
      setTimeout(() => {
        const user = mockUsers[0]; // Simulate first user login
        localStorage.setItem('typearena_user', JSON.stringify(user));
        resolve(user);
      }, 500);
    });
  } catch (error) {
    console.error('Login error:', error);
    throw error;
  }
};

export const signupUser = async (username, email, password, phoneNumber) => {
  try {
    // TODO: Replace with actual API call
    // const response = await fetch(`${API_BASE_URL}/auth/signup`, {
    //   method: 'POST',
    //   headers: { 'Content-Type': 'application/json' },
    //   body: JSON.stringify({ username, email, password, phoneNumber }),
    // });
    // return response.json();
    
    // Mock implementation
    return new Promise((resolve) => {
      setTimeout(() => {
        const newUser = {
          id: mockUsers.length + 1,
          username,
          email,
          phoneNumber,
          wpm: 0,
          accuracy: 0,
          totalRaces: 0,
          wins: 0,
          balance: 0,
        };
        localStorage.setItem('typearena_user', JSON.stringify(newUser));
        resolve(newUser);
      }, 500);
    });
  } catch (error) {
    console.error('Signup error:', error);
    throw error;
  }
};

// Tournament APIs
export const fetchTournaments = async () => {
  try {
    // TODO: Replace with actual API call
    // const response = await fetch(`${API_BASE_URL}/tournaments`);
    // return response.json();
    
    return new Promise((resolve) => {
      setTimeout(() => resolve(mockTournaments.map((t) => ({ ...t }))), 300);
    });
  } catch (error) {
    console.error('Error fetching tournaments:', error);
    return [];
  }
};

export const joinTournament = async (tournamentId) => {
  try {
    // TODO: Replace with actual API call
    // const response = await fetch(`${API_BASE_URL}/tournaments/${tournamentId}/join`, {
    //   method: 'POST',
    // });
    // return response.json();
    
    return new Promise((resolve, reject) => {
      setTimeout(() => {
        const tournament = mockTournaments.find((t) => t.id === tournamentId);
        if (!tournament) {
          reject(new Error('Tournament not found.'));
          return;
        }

        if (tournament.participants >= tournament.maxParticipants) {
          reject(new Error('This tournament is already full.'));
          return;
        }

        const storedUser = localStorage.getItem('typearena_user');
        if (!storedUser) {
          reject(new Error('Please sign in first to join this tournament.'));
          return;
        }

        const currentUser = JSON.parse(storedUser);
        if ((currentUser.balance ?? 0) < tournament.entryFee) {
          reject(new Error(`Insufficient balance. You need KES ${tournament.entryFee} to join.`));
          return;
        }

        const updatedUser = {
          ...currentUser,
          balance: currentUser.balance - tournament.entryFee,
        };
        localStorage.setItem('typearena_user', JSON.stringify(updatedUser));

        tournament.participants += 1;
        const isNowFull = tournament.participants >= tournament.maxParticipants;
        if (isNowFull) {
          tournament.status = 'active';
          tournament.startTime = new Date();
        }

        resolve({
          success: true,
          tournament: { ...tournament },
          user: updatedUser,
          message: isNowFull
            ? 'You have successfully joined this tournament. All required members have joined and the tournament is now starting.'
            : 'You have successfully joined this tournament. You will receive notification when it will start.',
        });
      }, 450);
    });
  } catch (error) {
    console.error('Error joining tournament:', error);
    throw error;
  }
};

// Leaderboard APIs
export const fetchLeaderboard = async (limit = 100) => {
  try {
    // TODO: Replace with actual API call
    // const response = await fetch(`${API_BASE_URL}/leaderboard?limit=${limit}`);
    // return response.json();
    
    return new Promise((resolve) => {
      setTimeout(() => resolve(mockLeaderboard), 300);
    });
  } catch (error) {
    console.error('Error fetching leaderboard:', error);
    return [];
  }
};

// Race/Results APIs
export const submitRaceResult = async (raceData) => {
  try {
    // TODO: Replace with actual API call
    // const response = await fetch(`${API_BASE_URL}/races/submit`, {
    //   method: 'POST',
    //   headers: { 'Content-Type': 'application/json' },
    //   body: JSON.stringify(raceData),
    // });
    // return response.json();
    
    return new Promise((resolve) => {
      setTimeout(() => {
        const result = {
          id: `race_${Date.now()}`,
          ...raceData,
          earnings: Math.round(Math.random() * 1000),
        };
        resolve(result);
      }, 300);
    });
  } catch (error) {
    console.error('Error submitting race result:', error);
    throw error;
  }
};

export const fetchRaceHistory = async (userId) => {
  try {
    // TODO: Replace with actual API call
    // const response = await fetch(`${API_BASE_URL}/users/${userId}/races`);
    // return response.json();
    
    return new Promise((resolve) => {
      setTimeout(() => resolve(mockRaceResults), 300);
    });
  } catch (error) {
    console.error('Error fetching race history:', error);
    return [];
  }
};

// User Profile APIs
export const fetchUserStats = async (userId) => {
  try {
    // TODO: Replace with actual API call
    // const response = await fetch(`${API_BASE_URL}/users/${userId}/stats`);
    // return response.json();
    
    return new Promise((resolve) => {
      setTimeout(() => {
        const user = mockUsers.find(u => u.id === userId) || mockUsers[0];
        resolve(user);
      }, 300);
    });
  } catch (error) {
    console.error('Error fetching user stats:', error);
    return null;
  }
};

export const updateUserProfile = async (userId, updates) => {
  try {
    // TODO: Replace with actual API call
    // const response = await fetch(`${API_BASE_URL}/users/${userId}`, {
    //   method: 'PUT',
    //   headers: { 'Content-Type': 'application/json' },
    //   body: JSON.stringify(updates),
    // });
    // return response.json();
    
    return new Promise((resolve) => {
      setTimeout(() => {
        const user = { ...mockUsers[0], ...updates };
        localStorage.setItem('typearena_user', JSON.stringify(user));
        resolve(user);
      }, 300);
    });
  } catch (error) {
    console.error('Error updating profile:', error);
    throw error;
  }
};

export const addFundsToWallet = async (amount) => {
  try {
    return new Promise((resolve, reject) => {
      setTimeout(() => {
        const storedUser = localStorage.getItem('typearena_user');
        if (!storedUser) {
          reject(new Error('Please sign in first.'));
          return;
        }

        const parsedAmount = Number(amount);
        if (!Number.isFinite(parsedAmount) || parsedAmount <= 0) {
          reject(new Error('Enter a valid amount greater than zero.'));
          return;
        }

        const user = JSON.parse(storedUser);
        const updatedUser = {
          ...user,
          balance: Number(user.balance || 0) + parsedAmount,
        };

        localStorage.setItem('typearena_user', JSON.stringify(updatedUser));
        resolve(updatedUser);
      }, 250);
    });
  } catch (error) {
    console.error('Error adding funds:', error);
    throw error;
  }
};
